\section{The structure sheaf of a $\Spec k$-scheme as a sheaf of $k$-modules}
\label{sec:scheme_toModuleKSheaf}

This section provides the substantive content of Phase~A step~5: for $C : \Over\,(\Spec\,(\CommRingCat\,k))$, equipping the structure sheaf $\struct C$ with a sheaf-of-$k$-modules structure via the algebra map induced by the structure morphism $C.\mathrm{hom} : C.\mathrm{left} \to \Spec\,(\CommRingCat\,k)$. Together with the typeclass plumbing of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} and Mathlib's \lstinline{CategoryTheory.Abelian.Ext.instModule}, this completes the typeclass chain that gives $H^1(C, \struct C)$ a $\Module k$ structure.

\subsection{The algebra map from the structure morphism}

For each open $U \subseteq C.\mathrm{left}$, the structure morphism induces a chain of ring maps
\[
  k \xrightarrow{(\Gamma\!\Spec\!\mathrm{Iso}\,k)^{-1}} \Gamma(\Spec\,k, \top) \xrightarrow{C.\mathrm{hom}.\mathrm{app}\,\top} \Gamma(C.\mathrm{left}, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C.\mathrm{left}, U),
\]
where $\rho$ is the restriction along $U \le C.\mathrm{hom}^{-1}\top = \top$. Mathlib's \lstinline{Scheme.\Gamma SpecIso} provides the first iso, and the rest is the ordinary \lstinline{Scheme.Hom.app} together with the action of the presheaf on the inclusion $U \le \top$.

\begin{definition}[Algebra map on a section]
  \label{def:Scheme_kToSection}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
  \uses{def:Scheme_toAbSheaf}
  Let $k$ be a commutative ring and $C : \Over\,(\Spec\,(\CommRingCat\,k))$. For any open $U$ of $C.\mathrm{left}$, define
  \[
    \mathtt{kToSection}\,C\,U \;\colon\; \CommRingCat\,k \;\longrightarrow\; \Gamma(C.\mathrm{left}, U)
  \]
  to be the composition $(\Gamma\!\Spec\!\mathrm{Iso}\,(\CommRingCat\,k))^{-1} \circ (C.\mathrm{hom}.\mathrm{app}\,\top) \circ \rho$, where $\rho$ is the restriction map of $C.\mathrm{left}$ from $\top$ to $U$.
\end{definition}

\begin{definition}[Algebra structure on a section]
  \label{def:Scheme_algebraSection}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
  \uses{def:Scheme_kToSection}
  The ring map $\mathtt{kToSection}\,C\,U$ exhibits $\Gamma(C.\mathrm{left}, U)$ as a $k$-algebra. We register the resulting $\Algebra\,k\,(\Gamma(C.\mathrm{left}, U))$ instance via \lstinline{RingHom.toAlgebra}.
\end{definition}

\begin{lemma}[Defining identity for the algebra map]
  \label{lem:Scheme_algebraMap_eq_kToSection}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
  \uses{def:Scheme_algebraSection}
  Under the algebra structure of Definition~\ref{def:Scheme_algebraSection},
  \[
    \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U)) \;=\; (\mathtt{kToSection}\,C\,U).\mathrm{hom}.
  \]
\end{lemma}

\begin{proof}
  \uses{def:Scheme_algebraSection}
  Definitionally true: \lstinline{RingHom.toAlgebra}$\,(f).\mathrm{algebraMap} = f$.
\end{proof}

\subsection{Naturality of the algebra map}

\begin{lemma}[Restriction is compatible with the algebra map]
  \label{lem:Scheme_kToSection_naturality}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection_naturality}
  \uses{def:Scheme_kToSection}
  For any $f : U \to V$ in $\opens(C.\mathrm{left})^{\mathrm{op}}$ (i.e.\ $V \le U$ in $\opens(C.\mathrm{left})$),
  \[
    \mathtt{kToSection}\,C\,U \,\circ\, C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f \;=\; \mathtt{kToSection}\,C\,V.
  \]
\end{lemma}

\begin{proof}
  \uses{def:Scheme_kToSection}
  Both sides factor through $C.\mathrm{hom}.\mathrm{app}\,\top : \Gamma(\Spec k, \top) \to \Gamma(C.\mathrm{left}, \top)$. The remaining triangle on $\opens(C.\mathrm{left})$ commutes by functoriality of $C.\mathrm{left}.\mathtt{presheaf}$ on the composable inclusions $V \le U \le \top$.
\end{proof}

\begin{lemma}[Algebra-map naturality]
  \label{lem:Scheme_algebraMap_naturality}
  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_naturality}
  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
  For any $f : U \to V$ in $\opens(C.\mathrm{left})^{\mathrm{op}}$ and $r \in k$,
  \[
    (C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f).\mathrm{hom}\bigl(\mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U))\,r\bigr) \;=\; \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, V))\,r.
  \]
\end{lemma}

\begin{proof}
  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
  Lemma~\ref{lem:Scheme_algebraMap_eq_kToSection} reduces both sides to the underlying ring map of $\mathtt{kToSection}$; Lemma~\ref{lem:Scheme_kToSection_naturality} then closes the goal by congruence.
\end{proof}

